 1	import type { FC, MouseEventHandler, ReactNode } from 'react';
 2	import classNames from 'classnames';
 3	
 4	import { Button, ButtonVariant, Popover, type PopoverProps } from '@patternfly/react-core';
 5	import { HelpIcon } from '@patternfly/react-icons';
 6	
 7	type HelpIconPopoverProps = {
 8	  children: ReactNode;
 9	  header?: ReactNode;
10	  popoverProps?: Omit<PopoverProps, 'bodyContent' | 'titleContent'>;
11	  onClick?: MouseEventHandler<HTMLButtonElement>;
12	  className?: string;
13	};
14	
15	export const HelpIconPopover: FC<HelpIconPopoverProps> = ({
16	  children,
17	  className,
18	  header,
19	  onClick,
20	  popoverProps,
21	}) => (
22	  <Popover position="right" bodyContent={children} headerContent={header} {...popoverProps}>
23	    <Button
24	      isInline
25	      variant={ButtonVariant.plain}
26	      icon={<HelpIcon />}
27	      onClick={onClick}
28	      className={classNames(
29	        'pf-v6-u-align-items-center',
30	        'pf-v6-u-p-0',
31	        'pf-v6-u-ml-sm',
32	        className,
33	      )}
34	    />
35	  </Popover>
36	);

